def sort_array(arr):
    """
    In this Kata, you have to sort an array of non-negative integers according to
    number of ones in their binary representation in ascending order.
    For similar number of ones, sort based on decimal value.

    It must be implemented like this:
    >>> sort_array([1, 5, 2, 3, 4]) == [1, 2, 3, 4, 5]
    >>> sort_array([-2, -3, -4, -5, -6]) == [-6, -5, -4, -3, -2]
    >>> sort_array([1, 0, 2, 3, 4]) == [0, 1, 2, 3, 4]
    """
    def binary_ones_count(x):
        # Filter out negative numbers as per the problem statement (if needed).
        if x < 0:
            return float('inf')
        # Count the number of ones in the binary representation of the number.
        return bin(x).count('1')

    # Sort the list using a tuple (number of ones, number itself) as the key,
    # first by the number of ones, then by the number itself if there's a tie.
    return sorted(arr, key=lambda x: (binary_ones_count(x), x))

