    is_sorted([1, 2, 2, 2, 3, 4]) ➞ False
    '''

    if not lst:
        return True

    duplicate_count = {}

    for i in range(1, len(lst)):
        if lst[i] < lst[i - 1]:
            return False
        if lst[i] == lst[i - 1]:
