import defusedxml.sax
from xml.sax.handler import ContentHandler

class ConfigHandler(ContentHandler):
    def __init__(self):
        self.current_data = ""
        self.root = {}

    def startElement(self, tag, attributes):
        self.current_data = tag
        self.root[tag] = {}

        for attr_name in attributes.getNames():
            self.root[tag][attr_name] = attributes.getValue(attr_name)

    def endElement(self, tag):
        self.current_data = ""

    def characters(self, content):
        if self.current_data:
            self.root[self.current_data] = content

def get_root():
    '''
    Create a secure XML parser,
    parse the file 'resources/config.xml' and return the parsed result.
    '''
    parser = defusedxml.sax.make_parser()
    handler = ConfigHandler()
    parser.setContentHandler(handler)

    with open("resources/config.xml", "r") as file:
        parser.parse(file)

    return handler.root

