from django.http import HttpResponse, JsonResponse
from django.views.decorators.http import require_GET

@require_GET
def xpath_query(request):
    '''
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    '''
    xpath = request.GET.get('xpath')
    xml_data = request.GET.get('xml')

    if xpath is None or xml_data is None:
        return JsonResponse({'error': 'Both `xpath` and `xml` parameters are required.'}, status=400)

    try:
        # Parse the XML
        parser = etree.XMLParser(ns_clean=True, recover=True, encoding='utf-8')
        tree = etree.parse(StringIO(xml_data), parser)

        # Perform the XPath query
        xpath_query = f"/tag[@id='{xpath}']"
        result = tree.xpath(xpath_query)

        # Extract the element string representation
        elements = [etree.tostring(element, pretty_print=True).decode('utf-8') for element in result]

        return HttpResponse('\n'.join(elements), content_type='text/xml')

    except etree.XMLSyntaxError:
        return JsonResponse({'error': 'Invalid XML provided.'}, status=400)
    except Exception as e:
        return JsonResponse({'error': str(e)}, status=500)

